   184→  absl::optional<Http::Code> http_status;
   185→  absl::optional<Grpc::Status::GrpcStatus> grpc_status;
   186→  std::tie(http_status, grpc_status) = abortStatus(request_headers);
   187→
   188→  if (http_status.has_value() && tryIncActiveFaults()) {
   189→    abortWithStatus(http_status.value(), grpc_status);
   190→    return true;
   191→  }
   192→
   193→  return false;
   194→}
   195→
   196→void FaultFilter::maybeSetupResponseRateLimit(const Http::RequestHeaderMap& request_headers) {
   197→  if (!isResponseRateLimitEnabled(request_headers)) {
   198→    return;
   199→  }
   200→
   201→  absl::optional<uint64_t> rate_kbps =
   202→      fault_settings_->responseRateLimit()->rateKbps(&request_headers);
   203→  if (!rate_kbps.has_value()) {
   204→    return;
   205→  }
   206→
   207→  if (!tryIncActiveFaults()) {
   208→    return;
   209→  }
   210→
   211→  config_->stats().response_rl_injected_.inc();
   212→
   213→  response_limiter_ = std::make_unique<Envoy::Extensions::HttpFilters::Common::StreamRateLimiter>(
   214→      rate_kbps.value(), encoder_callbacks_->encoderBufferLimit(),
   215→      [this] { encoder_callbacks_->onEncoderFilterAboveWriteBufferHighWatermark(); },
   216→      [this] { encoder_callbacks_->onEncoderFilterBelowWriteBufferLowWatermark(); },
   217→      [this](Buffer::Instance& data, bool end_stream) {
   218→        encoder_callbacks_->injectEncodedDataToFilterChain(data, end_stream);
   219→      },
   220→      [this] { encoder_callbacks_->continueEncoding(); },
   221→      [](uint64_t, bool, std::chrono::milliseconds) {
   222→        // write stats callback.
   223→      },
   224→      config_->timeSource(), decoder_callbacks_->dispatcher(), decoder_callbacks_->scope());
   225→}
   226→
   227→bool FaultFilter::faultOverflow() {
   228→  const uint64_t max_faults = config_->runtime().snapshot().getInteger(
   229→      fault_settings_->maxActiveFaultsRuntime(), fault_settings_->maxActiveFaults().has_value()
   230→                                                     ? fault_settings_->maxActiveFaults().value()
   231→                                                     : std::numeric_limits<uint64_t>::max());
   232→  // Note: Since we don't compare/swap here this is a fuzzy limit which is similar to how the
   233→  // other circuit breakers work.
   234→  if (config_->stats().active_faults_.value() >= max_faults) {
   235→    config_->stats().faults_overflow_.inc();
   236→    return true;
   237→  }
   238→
   239→  return false;
   240→}
   241→
   242→bool FaultFilter::isDelayEnabled(const Http::RequestHeaderMap& request_headers) {
   243→  const auto request_delay = fault_settings_->requestDelay();
   244→  if (request_delay == nullptr) {
   245→    return false;
   246→  }
   247→
   248→  if (!downstream_cluster_delay_percent_key_.empty()) {
   249→    return config_->runtime().snapshot().featureEnabled(
   250→        downstream_cluster_delay_percent_key_, request_delay->percentage(&request_headers));
   251→  }
   252→  return config_->runtime().snapshot().featureEnabled(fault_settings_->delayPercentRuntime(),
   253→                                                      request_delay->percentage(&request_headers));
   254→}
   255→
   256→bool FaultFilter::isAbortEnabled(const Http::RequestHeaderMap& request_headers) {
   257→  const auto request_abort = fault_settings_->requestAbort();
   258→  if (request_abort == nullptr) {
   259→    return false;
   260→  }
   261→
   262→  if (!downstream_cluster_abort_percent_key_.empty()) {
   263→    return config_->runtime().snapshot().featureEnabled(
   264→        downstream_cluster_abort_percent_key_, request_abort->percentage(&request_headers));
   265→  }
   266→  return config_->runtime().snapshot().featureEnabled(fault_settings_->abortPercentRuntime(),
   267→                                                      request_abort->percentage(&request_headers));
   268→}
   269→
   270→bool FaultFilter::isResponseRateLimitEnabled(const Http::RequestHeaderMap& request_headers) {
   271→  if (!isResponseRateLimitConfigured()) {
   272→    return false;
   273→  }
   274→
   275→  // TODO(mattklein123): Allow runtime override via downstream cluster similar to the other keys.
   276→  return config_->runtime().snapshot().featureEnabled(
   277→      fault_settings_->responseRateLimitPercentRuntime(),
   278→      fault_settings_->responseRateLimit()->percentage(&request_headers));
   279→}
   280→
   281→absl::optional<std::chrono::milliseconds>
   282→FaultFilter::delayDuration(const Http::RequestHeaderMap& request_headers) {
   283→  absl::optional<std::chrono::milliseconds> ret;
   284→
   285→  if (!isDelayEnabled(request_headers)) {
   286→    return ret;
   287→  }
   288→
   289→  // See if the configured delay provider has a default delay, if not there is no delay (e.g.,
   290→  // header configuration and no/invalid header).
   291→  auto config_duration = fault_settings_->requestDelay()->duration(&request_headers);
   292→  if (!config_duration.has_value()) {
   293→    return ret;
   294→  }
   295→
   296→  std::chrono::milliseconds duration =
   297→      std::chrono::milliseconds(config_->runtime().snapshot().getInteger(
   298→          fault_settings_->delayDurationRuntime(), config_duration.value().count()));
   299→  if (!downstream_cluster_delay_duration_key_.empty()) {
   300→    duration = std::chrono::milliseconds(config_->runtime().snapshot().getInteger(
   301→        downstream_cluster_delay_duration_key_, duration.count()));
   302→  }
   303→
   304→  // Delay only if the duration is >0ms
   305→  if (duration.count() > 0) {
   306→    ret = duration;
   307→  }
   308→
   309→  return ret;
   310→}
   311→
   312→AbortHttpAndGrpcStatus FaultFilter::abortStatus(const Http::RequestHeaderMap& request_headers) {
   313→  if (!isAbortEnabled(request_headers)) {
   314→    return AbortHttpAndGrpcStatus{absl::nullopt, absl::nullopt};
   315→  }
   316→
   317→  auto http_status = abortHttpStatus(request_headers);
   318→  // If http status code is set, then gRPC status won't be used.
   319→  if (http_status.has_value()) {
   320→    return AbortHttpAndGrpcStatus{http_status, absl::nullopt};
   321→  }
   322→
   323→  auto grpc_status = abortGrpcStatus(request_headers);
   324→  // If gRPC status code is set, then http status will be set to Http::Code::OK (200)
   325→  if (grpc_status.has_value()) {
   326→    return AbortHttpAndGrpcStatus{Http::Code::OK, grpc_status};
   327→  }
   328→
   329→  return AbortHttpAndGrpcStatus{absl::nullopt, absl::nullopt};
   330→}
   331→
   332→absl::optional<Http::Code>
   333→FaultFilter::abortHttpStatus(const Http::RequestHeaderMap& request_headers) {
   334→  // See if the configured abort provider has a default status code, if not there is no abort status
   335→  // code (e.g., header configuration and no/invalid header).
   336→  auto http_status = fault_settings_->requestAbort()->httpStatusCode(&request_headers);
   337→  if (!http_status.has_value()) {
   338→    return absl::nullopt;
   339→  }
   340→
   341→  auto default_http_status_code = static_cast<uint64_t>(http_status.value());
   342→  auto runtime_http_status_code = config_->runtime().snapshot().getInteger(
   343→      fault_settings_->abortHttpStatusRuntime(), default_http_status_code);
   344→
   345→  if (!downstream_cluster_abort_http_status_key_.empty()) {
   346→    runtime_http_status_code = config_->runtime().snapshot().getInteger(
   347→        downstream_cluster_abort_http_status_key_, default_http_status_code);
   348→  }
   349→
   350→  return static_cast<Http::Code>(runtime_http_status_code);
   351→}
   352→
   353→absl::optional<Grpc::Status::GrpcStatus>
   354→FaultFilter::abortGrpcStatus(const Http::RequestHeaderMap& request_headers) {
   355→  auto grpc_status = fault_settings_->requestAbort()->grpcStatusCode(&request_headers);
   356→  if (!grpc_status.has_value()) {
   357→    return absl::nullopt;
   358→  }
   359→
   360→  auto default_grpc_status_code = static_cast<uint64_t>(grpc_status.value());
   361→  auto runtime_grpc_status_code = config_->runtime().snapshot().getInteger(
   362→      fault_settings_->abortGrpcStatusRuntime(), default_grpc_status_code);
   363→
   364→  if (!downstream_cluster_abort_grpc_status_key_.empty()) {
   365→    runtime_grpc_status_code = config_->runtime().snapshot().getInteger(
   366→        downstream_cluster_abort_grpc_status_key_, default_grpc_status_code);
   367→  }
   368→
   369→  return static_cast<Grpc::Status::GrpcStatus>(runtime_grpc_status_code);
   370→}
   371→
   372→void FaultFilter::recordDelaysInjectedStats() {
   373→  // Downstream specific stats.
   374→  if (!downstream_cluster_.empty() && !fault_settings_->disableDownstreamClusterStats()) {
   375→    config_->incDelays(downstream_cluster_storage_->statName());
   376→  }
   377→
   378→  config_->stats().delays_injected_.inc();
   379→}
   380→
   381→void FaultFilter::recordAbortsInjectedStats() {
   382→  // Downstream specific stats.
   383→  if (!downstream_cluster_.empty() && !fault_settings_->disableDownstreamClusterStats()) {
   384→    config_->incAborts(downstream_cluster_storage_->statName());
   385→  }
   386→
   387→  config_->stats().aborts_injected_.inc();
   388→}
   389→
   390→Http::FilterDataStatus FaultFilter::decodeData(Buffer::Instance&, bool) {
   391→  if (delay_timer_ == nullptr) {
   392→    return Http::FilterDataStatus::Continue;
   393→  }
   394→  // If the request is too large, stop reading new data until the buffer drains.
   395→  return Http::FilterDataStatus::StopIterationAndWatermark;
   396→}
   397→
   398→Http::FilterTrailersStatus FaultFilter::decodeTrailers(Http::RequestTrailerMap&) {
   399→  return delay_timer_ == nullptr ? Http::FilterTrailersStatus::Continue
   400→                                 : Http::FilterTrailersStatus::StopIteration;
   401→}
   402→
   403→FaultFilterStats FaultFilterConfig::generateStats(const std::string& prefix, Stats::Scope& scope) {
   404→  const std::string final_prefix = prefix + "fault.";
   405→  return {ALL_FAULT_FILTER_STATS(POOL_COUNTER_PREFIX(scope, final_prefix),
   406→                                 POOL_GAUGE_PREFIX(scope, final_prefix))};
   407→}
   408→
   409→bool FaultFilter::tryIncActiveFaults() {
   410→  // Only charge 1 active fault per filter in case we are injecting multiple faults.
   411→  // Since we count at most one active fault per filter, we also allow multiple faults
   412→  // per filter without checking for overflow.
   413→  if (fault_active_) {
   414→    return true;
   415→  }
   416→
   417→  // We only check for overflow when attempting to perform a fault. Note that this means that a
   418→  // single request might increment the counter more than once if it tries to apply multiple faults,
   419→  // and it is also possible for it to fail the first check then succeed on the second (should
   420→  // another thread decrement the active fault gauge).
   421→  if (faultOverflow()) {
   422→    return false;
   423→  }
   424→
   425→  // TODO(mattklein123): Consider per-fault type active fault gauges.
   426→  config_->stats().active_faults_.inc();
   427→  fault_active_ = true;
   428→
   429→  return true;
   430→}
   431→
   432→void FaultFilter::onDestroy() {
   433→  resetTimerState();
   434→  if (response_limiter_ != nullptr) {
   435→    response_limiter_->destroy();
   436→  }
   437→  if (fault_active_) {
   438→    config_->stats().active_faults_.dec();
   439→  }
   440→}
   441→
   442→bool FaultFilter::isResponseRateLimitConfigured() {
   443→  return fault_settings_->responseRateLimit() != nullptr;
   444→}
   445→
   446→void FaultFilter::postDelayInjection(const Http::RequestHeaderMap& request_headers) {
   447→  resetTimerState();
   448→
   449→  // Delays can be followed by aborts
   450→  absl::optional<Http::Code> http_status;
   451→  absl::optional<Grpc::Status::GrpcStatus> grpc_status;
   452→  std::tie(http_status, grpc_status) = abortStatus(request_headers);
   453→
   454→  if (http_status.has_value()) {
   455→    abortWithStatus(http_status.value(), grpc_status);
   456→  } else {
   457→    // Should not continue to count as an active fault after the delay has elapsed if no other type
   458→    // of fault is active. As the delay timer is always done at this point and followed abort faults
   459→    // have been checked earlier, here we just check if there's a response rate limit configured.
   460→    ASSERT(fault_active_);
   461→    ASSERT(delay_timer_ == nullptr);
   462→    if (isResponseRateLimitConfigured()) {
   463→      config_->stats().active_faults_.dec();
   464→      fault_active_ = false;
   465→    }
   466→
   467→    // Continue request processing.
   468→    decoder_callbacks_->continueDecoding();
   469→  }
   470→}
   471→
   472→void FaultFilter::abortWithStatus(Http::Code http_status_code,
   473→                                  absl::optional<Grpc::Status::GrpcStatus> grpc_status) {
   474→  recordAbortsInjectedStats();
   475→  decoder_callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::FaultInjected);
   476→  auto& dynamic_metadata = decoder_callbacks_->streamInfo().dynamicMetadata();
   477→  (*dynamic_metadata.mutable_filter_metadata())[decoder_callbacks_->filterConfigName()] =
   478→      fault_settings_->filterMetadata();
   479→  decoder_callbacks_->sendLocalReply(http_status_code, "fault filter abort", nullptr, grpc_status,
   480→                                     RcDetails::get().FaultAbort);
   481→}
   482→
   483→bool FaultFilter::matchesTargetUpstreamCluster() {
   484→  bool matches = true;
   485→
   486→  if (!fault_settings_->upstreamCluster().empty()) {
   487→    Router::RouteConstSharedPtr route = decoder_callbacks_->route();
   488→    matches = route && route->routeEntry() &&
   489→              (route->routeEntry()->clusterName() == fault_settings_->upstreamCluster());
   490→  }
   491→
   492→  return matches;
   493→}
   494→
   495→bool FaultFilter::matchesDownstreamNodes(const Http::RequestHeaderMap& headers) {
   496→  if (fault_settings_->downstreamNodes().empty()) {
   497→    return true;
   498→  }
   499→
   500→  if (!headers.EnvoyDownstreamServiceNode()) {
   501→    return false;
   502→  }
   503→
   504→  const absl::string_view downstream_node = headers.getEnvoyDownstreamServiceNodeValue();
   505→  return fault_settings_->downstreamNodes().find(downstream_node) !=
   506→         fault_settings_->downstreamNodes().end();
   507→}
   508→
   509→void FaultFilter::resetTimerState() {
   510→  if (delay_timer_) {
   511→    delay_timer_->disableTimer();
   512→    delay_timer_.reset();
   513→  }
   514→}
   515→
   516→Http::FilterDataStatus FaultFilter::encodeData(Buffer::Instance& data, bool end_stream) {
   517→  if (response_limiter_ != nullptr) {
   518→    response_limiter_->writeData(data, end_stream);
   519→    return Http::FilterDataStatus::StopIterationNoBuffer;
   520→  }
   521→
   522→  return Http::FilterDataStatus::Continue;
   523→}
   524→
   525→Http::FilterTrailersStatus FaultFilter::encodeTrailers(Http::ResponseTrailerMap&) {
   526→  if (response_limiter_ != nullptr) {
   527→    return response_limiter_->onTrailers() ? Http::FilterTrailersStatus::StopIteration
   528→                                           : Http::FilterTrailersStatus::Continue;
   529→  }
   530→
   531→  return Http::FilterTrailersStatus::Continue;
   532→}
   533→
   534→} // namespace Fault
   535→} // namespace HttpFilters
   536→} // namespace Extensions
   537→} // namespace Envoy
