   289→bool HeaderUtility::rewriteAuthorityForConnectUdp(RequestHeaderMap& headers) {
   290→  // Per RFC 9298, the URI template must only contain ASCII characters in the range 0x21-0x7E.
   291→  absl::string_view path = headers.getPathValue();
   292→  for (char c : path) {
   293→    unsigned char ascii_code = static_cast<unsigned char>(c);
   294→    if (ascii_code < 0x21 || ascii_code > 0x7e) {
   295→      ENVOY_LOG_MISC(warn, "CONNECT-UDP request with a bad character in the path {}", path);
   296→      return false;
   297→    }
   298→  }
   299→
   300→  // Extract target host and port from path using default template.
   301→  if (!absl::StartsWith(path, "/.well-known/masque/udp/")) {
   302→    ENVOY_LOG_MISC(warn, "CONNECT-UDP request path is not a well-known URI: {}", path);
   303→    return false;
   304→  }
   305→
   306→  std::vector<absl::string_view> path_split = absl::StrSplit(path, '/');
   307→  if (path_split.size() != 7 || path_split[4].empty() || path_split[5].empty() ||
   308→      !path_split[6].empty()) {
   309→    ENVOY_LOG_MISC(warn, "CONNECT-UDP request with a malformed URI template in the path {}", path);
   310→    return false;
   311→  }
   312→
   313→  // Utility::PercentEncoding::decode never returns an empty string if the input argument is not
   314→  // empty.
   315→  std::string target_host = Utility::PercentEncoding::decode(path_split[4]);
   316→  // Per RFC 9298, IPv6 Zone ID is not supported.
   317→  if (target_host.find('%') != std::string::npos) {
   318→    ENVOY_LOG_MISC(warn, "CONNECT-UDP request with a non-escpaed char (%) in the path {}", path);
   319→    return false;
   320→  }
   321→  std::string target_port = Utility::PercentEncoding::decode(path_split[5]);
   322→
   323→  // If the host is an IPv6 address, surround the address with square brackets.
   324→  in6_addr sin6_addr;
   325→  bool is_ipv6 = (inet_pton(AF_INET6, target_host.c_str(), &sin6_addr) == 1);
   326→  std::string new_host =
   327→      absl::StrCat((is_ipv6 ? absl::StrCat("[", target_host, "]") : target_host), ":", target_port);
   328→  headers.setHost(new_host);
   329→
   330→  return true;
   331→}
