   386→  const absl::string_view port_str = original_host.substr(port_start + 1);
   387→  if (port_start == absl::string_view::npos) {
   388→    return false;
   389→  }
   390→  uint32_t port = 0;
   391→  if (!absl::SimpleAtoi(port_str, &port)) {
