   504→Http::Status HeaderUtility::checkRequiredRequestHeaders(const Http::RequestHeaderMap& headers) {
   505→  if (!headers.Method()) {
   506→    return absl::InvalidArgumentError(
   507→        absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Method.get()));
   508→  }
   509→  bool is_connect = Http::HeaderUtility::isConnect(headers);
   510→  if (is_connect) {
   511→    if (!headers.Host()) {
   512→      // Host header must be present for CONNECT request.
   513→      return absl::InvalidArgumentError(
   514→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Host.get()));
   515→    }
   516→    if (headers.Path() && !headers.Protocol()) {
   517→      // Path and Protocol header should only be present for CONNECT for upgrade style CONNECT.
   518→      return absl::InvalidArgumentError(
   519→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Protocol.get()));
   520→    }
   521→    if (!headers.Path() && headers.Protocol()) {
   522→      // Path and Protocol header should only be present for CONNECT for upgrade style CONNECT.
   523→      return absl::InvalidArgumentError(
   524→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Path.get()));
   525→    }
   526→  } else {
   527→    if (!headers.Path()) {
   528→      // :path header must be present for non-CONNECT requests.
   529→      return absl::InvalidArgumentError(
   530→          absl::StrCat("missing required header: ", Envoy::Http::Headers::get().Path.get()));
   531→    }
   532→  }
   533→  return Http::okStatus();
   534→}
   535→
   536→Http::Status HeaderUtility::checkValidRequestHeaders(const Http::RequestHeaderMap& headers) {
   537→  if (!Runtime::runtimeFeatureEnabled("envoy.reloadable_features.validate_upstream_headers")) {
   538→    return Http::okStatus();
   539→  }
   540→
   541→  const HeaderEntry* invalid_entry = nullptr;
   542→  bool invalid_key = false;
   543→  headers.iterate([&invalid_entry, &invalid_key](const HeaderEntry& header) -> HeaderMap::Iterate {
   544→    if (!HeaderUtility::headerNameIsValid(header.key().getStringView())) {
   545→      invalid_entry = &header;
   546→      invalid_key = true;
   547→      return HeaderMap::Iterate::Break;
   548→    }
   549→
   550→    if (!HeaderUtility::headerValueIsValid(header.value().getStringView())) {
   551→      invalid_entry = &header;
   552→      invalid_key = false;
   553→      return HeaderMap::Iterate::Break;
   554→    }
   555→
   556→    return HeaderMap::Iterate::Continue;
   557→  });
   558→
   559→  if (invalid_entry) {
   560→    // The header key may contain non-printable characters. Escape the key so that the error
   561→    // details can be safely presented.
   562→    const absl::string_view key = invalid_entry->key().getStringView();
   563→    uint64_t extra_length = JsonEscaper::extraSpace(key);
   564→    const std::string escaped_key = JsonEscaper::escapeString(key, extra_length);
   565→
   566→    return absl::InvalidArgumentError(
   567→        absl::StrCat("invalid header ", invalid_key ? "name: " : "value for: ", escaped_key));
   568→  }
   569→  return Http::okStatus();
   570→}
