   426→
   427→absl::string_view::size_type HeaderUtility::getPortStart(absl::string_view host) {
   428→  const absl::string_view::size_type port_start = host.rfind(':');
   429→  if (port_start == absl::string_view::npos) {
   430→    return absl::string_view::npos;
   431→  }
   432→  // According to RFC3986 v6 address is always enclosed in "[]". section 3.2.2.
   433→  const auto v6_end_index = host.rfind(']');
   434→  if (v6_end_index == absl::string_view::npos || v6_end_index < port_start) {
   435→    if ((port_start + 1) > host.size()) {
   436→      return absl::string_view::npos;
   437→    }
   438→    return port_start;
   439→  }
   440→  return absl::string_view::npos;
   441→}
