   593→    envoy::config::core::v3::HttpProtocolOptions::HeadersWithUnderscoresAction
   594→        headers_with_underscores_action,
   595→    HeaderValidatorStats& stats) {
   596→  if (headers_with_underscores_action == envoy::config::core::v3::HttpProtocolOptions::ALLOW ||
   597→      !HeaderUtility::headerNameContainsUnderscore(header_name)) {
   598→    return HeaderValidationResult::ACCEPT;
   599→  }
   600→  if (headers_with_underscores_action ==
   601→      envoy::config::core::v3::HttpProtocolOptions::DROP_HEADER) {
   602→    ENVOY_LOG_MISC(debug, "Dropping header with invalid characters in its name: {}", header_name);
   603→    stats.incDroppedHeadersWithUnderscores();
   604→    return HeaderValidationResult::DROP;
   605→  }
   606→  ENVOY_LOG_MISC(debug, "Rejecting request due to header name with underscores: {}", header_name);
   607→  stats.incRequestsRejectedWithUnderscoresInHeaders();
   608→  return HeaderUtility::HeaderValidationResult::REJECT;
   609→}
   610→
   611→HeaderUtility::HeaderValidationResult
   612→HeaderUtility::validateContentLength(absl::string_view header_value,
   613→                                     bool override_stream_error_on_invalid_http_message,
   614→                                     bool& should_close_connection, size_t& content_length_output) {
   615→  should_close_connection = false;
   616→  std::vector<absl::string_view> values = absl::StrSplit(header_value, ',');
   617→  absl::optional<uint64_t> content_length;
   618→  for (const absl::string_view& value : values) {
   619→    uint64_t new_value;
   620→    if (!absl::SimpleAtoi(value, &new_value) ||
   621→        !std::all_of(value.begin(), value.end(), absl::ascii_isdigit)) {
   622→      ENVOY_LOG_MISC(debug, "Content length was either unparseable or negative");
   623→      should_close_connection = !override_stream_error_on_invalid_http_message;
   624→      return HeaderValidationResult::REJECT;
   625→    }
   626→    if (!content_length.has_value()) {
   627→      content_length = new_value;
   628→      continue;
   629→    }
   630→    if (new_value != content_length.value()) {
   631→      ENVOY_LOG_MISC(
   632→          debug,
   633→          "Parsed content length {} is inconsistent with previously detected content length {}",
   634→          new_value, content_length.value());
   635→      should_close_connection = !override_stream_error_on_invalid_http_message;
   636→      return HeaderValidationResult::REJECT;
   637→    }
   638→  }
   639→  content_length_output = content_length.value();
   640→  return HeaderValidationResult::ACCEPT;
   641→}
   642→
   643→std::vector<absl::string_view>
   644→HeaderUtility::parseCommaDelimitedHeader(absl::string_view header_value) {
   645→  std::vector<absl::string_view> values;
   646→  for (absl::string_view s : absl::StrSplit(header_value, ',')) {
   647→    absl::string_view token = absl::StripAsciiWhitespace(s);
   648→    if (token.empty()) {
   649→      continue;
   650→    }
   651→    values.emplace_back(token);
   652→  }
   653→  return values;
   654→}
   655→
   656→absl::string_view HeaderUtility::getSemicolonDelimitedAttribute(absl::string_view value) {
   657→  return absl::StripAsciiWhitespace(StringUtil::cropRight(value, ";"));
   658→}
   659→
   660→std::string HeaderUtility::addEncodingToAcceptEncoding(absl::string_view accept_encoding_header,
   661→                                                       absl::string_view encoding) {
   662→  // Append the content encoding only if it isn't already present in the
   663→  // accept_encoding header. If it is present with a q-value ("gzip;q=0.3"),
   664→  // remove the q-value to indicate that the content encoding setting that we
   665→  // add has max priority (i.e. q-value 1.0).
   666→  std::vector<absl::string_view> newContentEncodings;
   667→  std::vector<absl::string_view> contentEncodings =
   668→      Http::HeaderUtility::parseCommaDelimitedHeader(accept_encoding_header);
   669→  for (absl::string_view contentEncoding : contentEncodings) {
   670→    absl::string_view strippedEncoding =
   671→        Http::HeaderUtility::getSemicolonDelimitedAttribute(contentEncoding);
   672→    if (strippedEncoding != encoding) {
   673→      // Add back all content encodings back except for the content encoding that we want to
   674→      // add. For example, if content encoding is "gzip", this filters out encodings "gzip" and
   675→      // "gzip;q=0.6".
   676→      newContentEncodings.push_back(contentEncoding);
   677→    }
   678→  }
   679→  // Finally add a single instance of our content encoding.
   680→  newContentEncodings.push_back(encoding);
   681→  return absl::StrJoin(newContentEncodings, ",");
   682→}
   683→
   684→bool HeaderUtility::isStandardConnectRequest(const Http::RequestHeaderMap& headers) {
   685→  return headers.getMethodValue() == Http::Headers::get().MethodValues.Connect &&
   686→         headers.getProtocolValue().empty();
   687→}
   688→
   689→bool HeaderUtility::isExtendedH2ConnectRequest(const Http::RequestHeaderMap& headers) {
   690→  return headers.getMethodValue() == Http::Headers::get().MethodValues.Connect &&
   691→         !headers.getProtocolValue().empty();
   692→}
   693→
   694→bool HeaderUtility::isPseudoHeader(absl::string_view header_name) {
   695→  return !header_name.empty() && header_name[0] == ':';
   696→}
   697→
   698→} // namespace Http
   699→} // namespace Envoy
