      0 /* CAN  */, 0 /* EM   */, 0 /* SUB  */, 0 /* ESC  */,
      0 /* FS   */, 0 /* GS   */, 0 /* RS   */, 0 /* US   */,
      0 /* SPC  */, 1 /* !    */, 0 /* "    */, 0 /* #    */,
