   349→Http::FilterHeadersStatus Filter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
   350→  ENVOY_STREAM_LOG(trace,
   351→                   "ext_authz filter has {} response header(s) to add and {} response header(s) to "
   352→                   "set to the encoded response:",
   353→                   *encoder_callbacks_, response_headers_to_add_.size(),
   354→                   response_headers_to_set_.size());
   355→  if (!response_headers_to_add_.empty()) {
   356→    ENVOY_STREAM_LOG(
   357→        trace, "ext_authz filter added header(s) to the encoded response:", *encoder_callbacks_);
   358→    for (const auto& [key, value] : response_headers_to_add_) {
   359→      ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
   360→      headers.addCopy(key, value);
   361→    }
   362→  }
   363→
   364→  if (!response_headers_to_set_.empty()) {
   365→    ENVOY_STREAM_LOG(
   366→        trace, "ext_authz filter set header(s) to the encoded response:", *encoder_callbacks_);
   367→    for (const auto& [key, value] : response_headers_to_set_) {
   368→      ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
   369→      headers.setCopy(key, value);
   370→    }
   371→  }
   372→
   373→  if (!response_headers_to_add_if_absent_.empty()) {
   374→    for (const auto& [key, value] : response_headers_to_add_if_absent_) {
   375→      ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key.get(), value);
   376→      if (auto header_entry = headers.get(key); header_entry.empty()) {
   377→        ENVOY_STREAM_LOG(trace, "ext_authz filter added header(s) to the encoded response:",
   378→                         *encoder_callbacks_);
   379→        headers.addCopy(key, value);
   380→      }
   381→    }
   382→  }
   383→
   384→  if (!response_headers_to_overwrite_if_exists_.empty()) {
   385→    for (const auto& [key, value] : response_headers_to_overwrite_if_exists_) {
   386→      ENVOY_STREAM_LOG(trace, "'{}':'{}'", *encoder_callbacks_, key, value);
   387→      if (auto header_entry = headers.get(key); !header_entry.empty()) {
   388→        ENVOY_STREAM_LOG(
   389→            trace, "ext_authz filter set header(s) to the encoded response:", *encoder_callbacks_);
   390→        headers.setCopy(key, value);
   391→      }
   392→    }
   393→  }
   394→  return Http::FilterHeadersStatus::Continue;
   395→}
