   459→CheckResult Filter::validateAndCheckDecoderHeaderMutation(
   460→    Filters::Common::MutationRules::CheckOperation operation, absl::string_view key,
   461→    absl::string_view value) const {
   462→  if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   463→                                       !Http::HeaderUtility::headerValueIsValid(value))) {
   464→    return CheckResult::FAIL;
   465→  }
   466→  // Check header mutation is valid according to configured decoder mutation rules.
   467→  return config_->checkDecoderHeaderMutation(operation, Http::LowerCaseString(key), value);
   468→}
   469→
   470→void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
   471→  state_ = State::Complete;
   472→  using Filters::Common::ExtAuthz::CheckStatus;
   473→  Stats::StatName empty_stat_name;
   474→
   475→  updateLoggingInfo();
   476→
   477→  if (!response->dynamic_metadata.fields().empty()) {
   478→    if (!config_->enableDynamicMetadataIngestion()) {
   479→      ENVOY_STREAM_LOG(trace,
   480→                       "Response is trying to inject dynamic metadata, but dynamic metadata "
   481→                       "ingestion is disabled. Ignoring...",
   482→                       *decoder_callbacks_);
   483→      stats_.ignored_dynamic_metadata_.inc();
   484→    } else {
   485→      // Add duration of call to dynamic metadata if applicable
   486→      if (start_time_.has_value() && response->status == CheckStatus::OK) {
   487→        ProtobufWkt::Value ext_authz_duration_value;
   488→        auto duration =
   489→            decoder_callbacks_->dispatcher().timeSource().monotonicTime() - start_time_.value();
   490→        ext_authz_duration_value.set_number_value(
   491→            std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
   492→        (*response->dynamic_metadata.mutable_fields())["ext_authz_duration"] =
   493→            ext_authz_duration_value;
   494→      }
   495→      decoder_callbacks_->streamInfo().setDynamicMetadata("envoy.filters.http.ext_authz",
   496→                                                          response->dynamic_metadata);
   497→    }
   498→  }
   499→
   500→  switch (response->status) {
   501→  case CheckStatus::OK: {
   502→    // Any changes to request headers or query parameters can affect how the request is going to be
   503→    // routed. Route cache clearing handled by downstream filters.
   504→
   505→    ENVOY_STREAM_LOG(trace,
   506→                     "ext_authz filter added header(s) to the request:", *decoder_callbacks_);
   507→    for (const auto& [key, value] : response->headers_to_set) {
   508→      CheckResult check_result = validateAndCheckDecoderHeaderMutation(
   509→          Filters::Common::MutationRules::CheckOperation::SET, key, value);
   510→      switch (check_result) {
   511→      case CheckResult::OK:
   512→        ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
   513→        request_headers_->setCopy(Http::LowerCaseString(key), value);
   514→        break;
   515→      case CheckResult::IGNORE:
   516→        ENVOY_STREAM_LOG(trace, "Ignoring invalid header to set '{}':'{}'.", *decoder_callbacks_,
   517→                         key, value);
   518→        break;
   519→      case CheckResult::FAIL:
   520→        ENVOY_STREAM_LOG(trace, "Rejecting invalid header to set '{}':'{}'.", *decoder_callbacks_,
   521→                         key, value);
   522→        rejectResponse();
   523→        return;
   524→      }
   525→    }
   526→    for (const auto& [key, value] : response->headers_to_add) {
   527→      CheckResult check_result = validateAndCheckDecoderHeaderMutation(
   528→          Filters::Common::MutationRules::CheckOperation::SET, key, value);
   529→      switch (check_result) {
   530→      case CheckResult::OK:
   531→        ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
   532→        request_headers_->addCopy(Http::LowerCaseString(key), value);
   533→        break;
   534→      case CheckResult::IGNORE:
   535→        ENVOY_STREAM_LOG(trace, "Ignoring invalid header to add '{}':'{}'.", *decoder_callbacks_,
   536→                         key, value);
   537→        break;
   538→      case CheckResult::FAIL:
   539→        ENVOY_STREAM_LOG(trace, "Rejecting invalid header to add '{}':'{}'.", *decoder_callbacks_,
   540→                         key, value);
   541→        rejectResponse();
   542→        return;
   543→      }
   544→    }
   545→    for (const auto& [key, value] : response->headers_to_append) {
   546→      CheckResult check_result = validateAndCheckDecoderHeaderMutation(
   547→          Filters::Common::MutationRules::CheckOperation::APPEND, key, value);
   548→      switch (check_result) {
   549→      case CheckResult::OK: {
   550→        ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
   551→        Http::LowerCaseString lowercase_key(key);
   552→        const auto header_to_modify = request_headers_->get(lowercase_key);
   553→        // TODO(dio): Add a flag to allow appending non-existent headers, without setting it
   554→        // first (via `headers_to_add`). For example, given:
   555→        // 1. Original headers {"original": "true"}
   556→        // 2. Response headers from the authorization servers {{"append": "1"}, {"append":
   557→        // "2"}}
   558→        //
   559→        // Currently it is not possible to add {{"append": "1"}, {"append": "2"}} (the
   560→        // intended combined headers: {{"original": "true"}, {"append": "1"}, {"append":
   561→        // "2"}}) to the request to upstream server by only sets `headers_to_append`.
   562→        if (!header_to_modify.empty()) {
   563→          ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
   564→          // The current behavior of appending is by combining entries with the same key,
   565→          // into one entry. The value of that combined entry is separated by ",".
   566→          // TODO(dio): Consider to use addCopy instead.
   567→          request_headers_->appendCopy(lowercase_key, value);
   568→        }
   569→        break;
   570→      }
   571→      case CheckResult::IGNORE:
   572→        ENVOY_STREAM_LOG(trace, "Ignoring invalid header to append '{}':'{}'.", *decoder_callbacks_,
   573→                         key, value);
   574→        break;
   575→      case CheckResult::FAIL:
   576→        ENVOY_STREAM_LOG(trace, "Rejecting invalid header to append '{}':'{}'.",
   577→                         *decoder_callbacks_, key, value);
   578→        rejectResponse();
   579→        return;
   580→      }
   581→    }
   582→
   583→    ENVOY_STREAM_LOG(trace,
   584→                     "ext_authz filter removed header(s) from the request:", *decoder_callbacks_);
   585→    for (const auto& key : response->headers_to_remove) {
   586→      // If the response contains an invalid header to remove, it's the same as trying to remove a
   587→      // header that doesn't exist, so just ignore it.
   588→      if (config_->validateMutations() && !Http::HeaderUtility::headerNameIsValid(key)) {
   589→        ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
   590→        continue;
   591→      }
   592→      // Header mutation rules handle validation if configured.
   593→      // Check header mutation is valid according to configured decoder header mutation rules.
   594→      Http::LowerCaseString lowercase_key(key);
   595→      switch (config_->checkDecoderHeaderMutation(CheckOperation::REMOVE, lowercase_key,
   596→                                                  EMPTY_STRING)) {
   597→      case CheckResult::OK:
   598→        ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
   599→        request_headers_->remove(lowercase_key);
   600→        break;
   601→      case CheckResult::IGNORE:
   602→        ENVOY_STREAM_LOG(trace, "Ignoring disallowed header removal '{}'.", *decoder_callbacks_,
   603→                         key);
   604→        break;
   605→      case CheckResult::FAIL:
   606→        ENVOY_STREAM_LOG(trace, "Rejecting disallowed header removal '{}'.", *decoder_callbacks_,
   607→                         key);
   608→        rejectResponse();
   609→        return;
   610→      }
   611→    }
   612→
   613→    if (!response->response_headers_to_add.empty()) {
   614→      ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
   615→                       *decoder_callbacks_, response->response_headers_to_add.size());
   616→      for (const auto& [key, value] : response->response_headers_to_add) {
   617→        if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   618→                                             !Http::HeaderUtility::headerValueIsValid(value))) {
   619→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   620→                           value);
   621→          rejectResponse();
   622→          return;
   623→        }
   624→      }
   625→      response_headers_to_add_ = Http::HeaderVector{response->response_headers_to_add.begin(),
   626→                                                    response->response_headers_to_add.end()};
   627→    }
   628→
   629→    if (!response->response_headers_to_set.empty()) {
   630→      ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
   631→                       *decoder_callbacks_, response->response_headers_to_set.size());
   632→      for (const auto& [key, value] : response->response_headers_to_set) {
   633→        if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   634→                                             !Http::HeaderUtility::headerValueIsValid(value))) {
   635→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   636→                           value);
   637→          rejectResponse();
   638→          return;
   639→        }
   640→      }
   641→      response_headers_to_set_ = Http::HeaderVector{response->response_headers_to_set.begin(),
   642→                                                    response->response_headers_to_set.end()};
   643→    }
   644→
   645→    if (!response->response_headers_to_add_if_absent.empty()) {
   646→      ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
   647→                       *decoder_callbacks_, response->response_headers_to_add_if_absent.size());
   648→      for (const auto& [key, value] : response->response_headers_to_add_if_absent) {
   649→        if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   650→                                             !Http::HeaderUtility::headerValueIsValid(value))) {
   651→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   652→                           value);
   653→          rejectResponse();
   654→          return;
   655→        }
   656→      }
   657→      response_headers_to_add_if_absent_ =
   658→          Http::HeaderVector{response->response_headers_to_add_if_absent.begin(),
   659→                             response->response_headers_to_add_if_absent.end()};
   660→    }
   661→
   662→    if (!response->response_headers_to_overwrite_if_exists.empty()) {
   663→      ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to set to the response:",
   664→                       *decoder_callbacks_,
   665→                       response->response_headers_to_overwrite_if_exists.size());
   666→      for (const auto& [key, value] : response->response_headers_to_overwrite_if_exists) {
   667→        if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
   668→                                             !Http::HeaderUtility::headerValueIsValid(value))) {
   669→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   670→                           value);
   671→          rejectResponse();
   672→          return;
   673→        }
   674→      }
   675→      response_headers_to_overwrite_if_exists_ =
   676→          Http::HeaderVector{response->response_headers_to_overwrite_if_exists.begin(),
   677→                             response->response_headers_to_overwrite_if_exists.end()};
   678→    }
   679→
   680→    absl::optional<Http::Utility::QueryParamsMulti> modified_query_parameters;
   681→    if (!response->query_parameters_to_set.empty()) {
   682→      modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
   683→          request_headers_->Path()->value().getStringView());
   684→      ENVOY_STREAM_LOG(
   685→          trace, "ext_authz filter set query parameter(s) on the request:", *decoder_callbacks_);
   686→      for (const auto& [key, value] : response->query_parameters_to_set) {
   687→        if (config_->validateMutations() &&
   688→            (!Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(key) ||
   689→             !Http::Utility::PercentEncoding::queryParameterIsUrlEncoded(value))) {
   690→          ENVOY_STREAM_LOG(trace, "Rejected invalid query parameter {}={}.", *decoder_callbacks_,
   691→                           key, value);
   692→          rejectResponse();
   693→          return;
   694→        }
   695→        ENVOY_STREAM_LOG(trace, "'{}={}'", *decoder_callbacks_, key, value);
   696→        modified_query_parameters->overwrite(key, value);
   697→      }
   698→    }
   699→
   700→    if (!response->query_parameters_to_remove.empty()) {
   701→      if (!modified_query_parameters) {
   702→        modified_query_parameters = Http::Utility::QueryParamsMulti::parseQueryString(
   703→            request_headers_->Path()->value().getStringView());
   704→      }
   705→      ENVOY_STREAM_LOG(trace, "ext_authz filter removed query parameter(s) from the request:",
   706→                       *decoder_callbacks_);
   707→      for (const auto& key : response->query_parameters_to_remove) {
   708→        ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
   709→        modified_query_parameters->remove(key);
   710→      }
   711→    }
   712→
   713→    // We modified the query parameters in some way, so regenerate the `path` header and set it
   714→    // here.
   715→    if (modified_query_parameters) {
   716→      const auto new_path =
   717→          modified_query_parameters->replaceQueryString(request_headers_->Path()->value());
   718→      ENVOY_STREAM_LOG(
   719→          trace, "ext_authz filter modified query parameter(s), using new path for request: {}",
   720→          *decoder_callbacks_, new_path);
   721→      request_headers_->setPath(new_path);
   722→    }
   723→
   724→    if (cluster_) {
   725→      config_->incCounter(cluster_->statsScope(), config_->ext_authz_ok_);
   726→    }
   727→    stats_.ok_.inc();
   728→    continueDecoding();
   729→    break;
   730→  }
   731→
   732→  case CheckStatus::Denied: {
   733→    ENVOY_STREAM_LOG(trace, "ext_authz filter rejected the request. Response status code: '{}'",
   734→                     *decoder_callbacks_, enumToInt(response->status_code));
   735→    stats_.denied_.inc();
   736→
   737→    if (cluster_) {
   738→      config_->incCounter(cluster_->statsScope(), config_->ext_authz_denied_);
   739→      if (config_->chargeClusterResponseStats()) {
   740→        Http::CodeStats::ResponseStatInfo info{config_->scope(),
   741→                                               cluster_->statsScope(),
   742→                                               empty_stat_name,
   743→                                               enumToInt(response->status_code),
   744→                                               true,
   745→                                               empty_stat_name,
   746→                                               empty_stat_name,
   747→                                               empty_stat_name,
   748→                                               empty_stat_name,
   749→                                               empty_stat_name,
   750→                                               false};
   751→        config_->httpContext().codeStats().chargeResponseStat(info, false);
   752→      }
   753→    }
   754→
   755→    // Check headers are valid.
   756→    if (config_->validateMutations()) {
   757→      for (const auto& [key, value] : response->headers_to_set) {
   758→        if (!Http::HeaderUtility::headerNameIsValid(key) ||
   759→            !Http::HeaderUtility::headerValueIsValid(value)) {
   760→          ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
   761→                           value);
   762→          rejectResponse();
   763→          return;
   764→        }
   765→      }
   766→    }
   767→
   768→    // setResponseFlag must be called before sendLocalReply
   769→    decoder_callbacks_->streamInfo().setResponseFlag(
   770→        StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
   771→    decoder_callbacks_->sendLocalReply(
   772→        response->status_code, response->body,
   773→        [&headers = response->headers_to_set,
   774→         &callbacks = *decoder_callbacks_](Http::HeaderMap& response_headers) -> void {
   775→          ENVOY_STREAM_LOG(trace,
   776→                           "ext_authz filter added header(s) to the local response:", callbacks);
   777→          // Firstly, remove all headers requested by the ext_authz filter, to ensure that they will
   778→          // override existing headers.
   779→          for (const auto& [key, _] : headers) {
   780→            response_headers.remove(Http::LowerCaseString(key));
   781→          }
   782→          // Then set all of the requested headers, allowing the same header to be set multiple
   783→          // times, e.g. `Set-Cookie`.
   784→          for (const auto& [key, value] : headers) {
   785→            ENVOY_STREAM_LOG(trace, " '{}':'{}'", callbacks, key, value);
   786→            response_headers.addCopy(Http::LowerCaseString(key), value);
   787→          }
   788→        },
   789→        absl::nullopt, Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzDenied);
   790→    break;
   791→  }
   792→
   793→  case CheckStatus::Error: {
   794→    if (cluster_) {
   795→      config_->incCounter(cluster_->statsScope(), config_->ext_authz_error_);
   796→    }
   797→    stats_.error_.inc();
   798→    if (config_->failureModeAllow()) {
   799→      ENVOY_STREAM_LOG(trace, "ext_authz filter allowed the request with error",
   800→                       *decoder_callbacks_);
   801→      stats_.failure_mode_allowed_.inc();
   802→      if (cluster_) {
   803→        config_->incCounter(cluster_->statsScope(), config_->ext_authz_failure_mode_allowed_);
   804→      }
   805→      if (config_->failureModeAllowHeaderAdd()) {
   806→        request_headers_->addReferenceKey(
   807→            Filters::Common::ExtAuthz::Headers::get().EnvoyAuthFailureModeAllowed, "true");
   808→      }
   809→      continueDecoding();
   810→    } else {
   811→      ENVOY_STREAM_LOG(
   812→          trace, "ext_authz filter rejected the request with an error. Response status code: {}",
   813→          *decoder_callbacks_, enumToInt(config_->statusOnError()));
   814→      decoder_callbacks_->streamInfo().setResponseFlag(
   815→          StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
   816→      decoder_callbacks_->sendLocalReply(
   817→          config_->statusOnError(), EMPTY_STRING, nullptr, absl::nullopt,
   818→          Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzError);
   819→    }
   820→    break;
   821→  }
   822→  }
   823→}
   824→
   825→void Filter::rejectResponse() {
   826→  const Http::Code status = Http::Code::InternalServerError;
   827→  ENVOY_STREAM_LOG(trace, "ext_authz filter invalidated the response. Response status code: {}",
   828→                   *decoder_callbacks_, enumToInt(status));
   829→  if (cluster_) {
   830→    config_->incCounter(cluster_->statsScope(), config_->ext_authz_invalid_);
   831→  }
   832→  stats_.invalid_.inc();
   833→  decoder_callbacks_->streamInfo().setResponseFlag(
   834→      StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
   835→  decoder_callbacks_->sendLocalReply(
   836→      status, EMPTY_STRING, nullptr, absl::nullopt,
   837→      Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzInvalid);
   838→}
   839→
   840→bool Filter::isBufferFull(uint64_t num_bytes_processing) const {
   841→  if (!allow_partial_message_) {
   842→    return false;
   843→  }
   844→
   845→  uint64_t num_bytes_buffered = num_bytes_processing;
   846→  const auto* buffer = decoder_callbacks_->decodingBuffer();
   847→  if (buffer != nullptr) {
   848→    num_bytes_buffered += buffer->length();
   849→  }
   850→
   851→  return num_bytes_buffered >= max_request_bytes_;
   852→}
   853→
   854→void Filter::continueDecoding() {
   855→  // After sending the check request, we don't need to buffer the data anymore.
   856→  buffer_data_ = false;
   857→
   858→  filter_return_ = FilterReturn::ContinueDecoding;
   859→  if (!initiating_call_) {
   860→    decoder_callbacks_->continueDecoding();
   861→  }
   862→}
   863→
   864→Filter::PerRouteFlags Filter::getPerRouteFlags(const Router::RouteConstSharedPtr& route) const {
   865→  if (route == nullptr) {
   866→    return PerRouteFlags{
   867→        true /*skip_check_*/,
   868→        envoy::extensions::filters::http::ext_authz::v3::CheckSettings() /*check_settings_*/};
   869→  }
   870→
   871→  const auto* specific_check_settings =
   872→      Http::Utility::resolveMostSpecificPerFilterConfig<FilterConfigPerRoute>(decoder_callbacks_);
   873→  if (specific_check_settings != nullptr) {
   874→    return PerRouteFlags{specific_check_settings->disabled(),
   875→                         specific_check_settings->checkSettings()};
   876→  }
   877→
   878→  return PerRouteFlags{
   879→      false /*skip_check_*/,
   880→      envoy::extensions::filters::http::ext_authz::v3::CheckSettings() /*check_settings_*/};
   881→}
   882→
   883→} // namespace ExtAuthz
   884→} // namespace HttpFilters
   885→} // namespace Extensions
   886→} // namespace Envoy
