   281→  request_headers_ = &headers;
   282→  const auto check_settings = per_route_flags.check_settings_;
   283→  buffer_data_ = (config_->withRequestBody() || check_settings.has_with_request_body()) &&
   284→                 !check_settings.disable_request_body_buffering() &&
   285→                 !(end_stream || Http::Utility::isWebSocketUpgradeRequest(headers) ||
   286→                   Http::Utility::isH2UpgradeRequest(headers));
