   288→  max_request_bytes_ = config_->maxRequestBytes();
   289→  if (buffer_data_) {
   290→    ENVOY_STREAM_LOG(debug, "ext_authz filter is buffering the request", *decoder_callbacks_);
   291→
   292→    allow_partial_message_ = check_settings.has_with_request_body()
   293→                                 ? check_settings.with_request_body().allow_partial_message()
   294→                                 : config_->allowPartialMessage();
